draw(C--P,Arrow(6));

dot("$(-4,-2)$", V, SW);
dot("$(0,5)$", C, E);
dot("$\begin{pmatrix} \frac{17}{10} \\ -\frac{51}{10} \end{pmatrix}$", P, NE);
[/asy]

